content:
## Actor

- id: {{ actor.id }}
- name: {{ actor.name }}
- description: {{ actor.description }}
- public state: {{ actor.public_state }}
- private state: {{ actor.private_state }}
- current activity: {{ actor.current_activity.name }}

## User input

{{ user_input }}

## World time

{{ world_time }}

## Location

- id: {{ location.id }}
- name: {{ location.name }}
- description: {{ location.description }}

## Inventory items held by actor

{% for entry in inventory %}
- stack id: {{ entry.stack_id }}; item id: {{ entry.item_id }}; {{ entry.name }} x{{ entry.quantity }}{% if entry.quality %}; quality: {{ entry.quality }}{% endif %}; description: {{ entry.description }}
{% else %}
- none
{% endfor %}

## Equipment held or worn by actor

{% for entry in equipment %}
- id: {{ entry.id }}; {{ entry.name }}; equipped: {{ entry.equipped }}{% if entry.equipped_position %}; position: {{ entry.equipped_position }}{% endif %}; description: {{ entry.description }}{% if entry.quality %}; quality: {{ entry.quality }}{% endif %}
{% else %}
- none
{% endfor %}

## Intents

{% for entry in intents %}
- id: {{ entry.intent.id }}; name: {{ entry.intent.name }}; type: {{ entry.intent.type }}; status: {{ entry.intent.status }}; horizon: {{ entry.intent.horizon }}; priority: {{ entry.intent.priority }}; urgency: {{ entry.intent.urgency }}{% if entry.intent.deadline %}; deadline: {{ entry.intent.deadline }}{% endif %}; recall sources: {{ entry.recall_sources }}{% if entry.similarity is not none %}; similarity: {{ entry.similarity }}{% endif %}
  description: {{ entry.intent.description }}
{% if entry.intent.desired_state %}  desired state: {{ entry.intent.desired_state }}
{% endif %}  success conditions: {{ entry.intent.success_conditions }}
  failure conditions: {{ entry.intent.failure_conditions }}
  maintenance conditions: {{ entry.intent.maintenance_conditions }}
  constraints: {{ entry.intent.constraints }}
  current plan: {{ entry.intent.current_plan }}
  next action biases: {{ entry.intent.next_action_biases }}
  blockers: {{ entry.intent.blockers }}
  open threads: {{ entry.intent.open_threads }}
{% else %}
- none
{% endfor %}

## Perceived characters

{% for entry in perceived_characters %}
- id: {{ entry.character.id }}; name: {{ entry.character.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; distance: {{ entry.distance_hint }}{% endif %}; state: {{ entry.character.public_state }}; affordances: {{ entry.affordances }}{% if entry.notes %}; notes: {{ entry.notes }}{% endif %}
  equipped gear:
{% for equipment in entry.visible_equipment %}
  - id: {{ equipment.id }}; {{ equipment.name }}{% if equipment.equipped_position %}; position: {{ equipment.equipped_position }}{% endif %}; description: {{ equipment.description }}
{% else %}
  - none visible
{% endfor %}
{% else %}
- none
{% endfor %}

## Perceived background characters

{% for entry in perceived_background_characters %}
- id: {{ entry.character.id }}; name: {{ entry.character.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; distance: {{ entry.distance_hint }}{% endif %}; description: {{ entry.character.description }}; affordances: {{ entry.affordances }}{% if entry.notes %}; notes: {{ entry.notes }}{% endif %}
{% else %}
- none
{% endfor %}

## Perceived direct-location item stacks

{% for entry in perceived_items %}
- stack id: {{ entry.stack.id }}; item id: {{ entry.item.id }}; {{ entry.item.name }} x{{ entry.stack.quantity }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; distance: {{ entry.distance_hint }}{% endif %}; owned by actor: {{ entry.owned_by_actor }}; affordances: {{ entry.affordances }}{% if entry.notes %}; notes: {{ entry.notes }}{% endif %}
{% else %}
- none
{% endfor %}

## Perceived direct-location equipment

{% for entry in perceived_equipment %}
- id: {{ entry.equipment.id }}; {{ entry.equipment.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; distance: {{ entry.distance_hint }}{% endif %}; owned by actor: {{ entry.owned_by_actor }}; affordances: {{ entry.affordances }}{% if entry.notes %}; notes: {{ entry.notes }}{% endif %}
{% else %}
- none
{% endfor %}

## Perceived direct-location containers

{% for entry in perceived_containers %}
- id: {{ entry.container.id }}; {{ entry.container.name }}; state: {{ entry.container.state }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; distance: {{ entry.distance_hint }}{% endif %}; owned by actor: {{ entry.owned_by_actor }}; affordances: {{ entry.affordances }}{% if entry.notes %}; notes: {{ entry.notes }}{% endif %}
{% else %}
- none
{% endfor %}

## Perceived landmarks

{% for entry in perceived_landmarks %}
- id: {{ entry.landmark.id }}; {{ entry.landmark.name }}; visibility: {{ entry.visibility }}; salience: {{ entry.salience }}{% if entry.distance_hint %}; distance: {{ entry.distance_hint }}{% endif %}; affordances: {{ entry.affordances }}{% if entry.notes %}; notes: {{ entry.notes }}{% endif %}
{% else %}
- none
{% endfor %}

## Recalled memories

{% for entry in relevant_memories %}
- memory id: {{ entry.memory.id }}; summary: {{ entry.memory.summary }}; event: {{ entry.event_name }}; support: {{ entry.support_type }}; confidence: {{ entry.confidence }}; decayed confidence: {{ entry.decayed_confidence }}; salience: {{ entry.salience }}; stance: {{ entry.stance }}; recall sources: {{ entry.recall_sources }}{% if entry.similarity is not none %}; similarity: {{ entry.similarity }}{% endif %}{% if entry.behavioural_relevance %}; behavioural relevance: {{ entry.behavioural_relevance }}{% endif %}
{% else %}
- none
{% endfor %}

## Recent events

{% for event in recent_events %}
- {{ event }}
{% else %}
- none
{% endfor %}

## Hard constraints

{% for constraint in hard_constraints %}
- {{ constraint }}
{% else %}
- none
{% endfor %}

## Soft constraints

{% for constraint in soft_constraints %}
- {{ constraint }}
{% else %}
- none
{% endfor %}
